import type { CatalogueData, FloorResponse, ItemResponse, RoomResponse } from './types';

// Bundled demo data, used when the API is unreachable so the experience still
// works as a standalone showcase. Snapshotted from the live seeded database
// (Database/PostDeploymentScripts/Seed_*.sql, as published to the local Docker
// SQL Server container): Location → Floor (levelIndex) → Room → Container
// (nestable) → Item, with real plan geometry in inches.
// rowVersion values are placeholder base64 (concurrency tokens are meaningless
// against demo data since there's no API to send them back to).

const RV = 'AAAAAAAAB9E=';
const CREATED = '2026-06-29T06:07:41Z';

function floor(
  id: number,
  locationId: number,
  name: string,
  levelIndex: number,
  elevationInches: number | null,
  ceilingHeightInches: number | null,
): FloorResponse {
  return { id, name, locationId, levelIndex, elevationInches, ceilingHeightInches, rowVersion: RV };
}

function room(
  id: number,
  name: string,
  floorId: number,
  roomType: number | null,
  geometry?: Partial<Pick<RoomResponse, 'originXInches' | 'originYInches' | 'widthInches' | 'depthInches' | 'heightInches' | 'wallColor' | 'floorColor'>>,
  description: string | null = null,
): RoomResponse {
  return {
    id,
    name,
    description,
    floorId,
    roomType,
    originXInches: null,
    originYInches: null,
    widthInches: null,
    depthInches: null,
    heightInches: null,
    rotation: 0,
    wallColor: null,
    floorColor: null,
    ceilingColor: null,
    rowVersion: RV,
    ...geometry,
  };
}

function mkItem(p: Partial<ItemResponse> & Pick<ItemResponse, 'id' | 'name'>): ItemResponse {
  return {
    description: null,
    itemTypes: [],
    purchasePrice: null,
    currentValue: null,
    brand: null,
    model: null,
    serialNumber: null,
    purchasedFrom: null,
    quantity: 1,
    condition: null,
    acquisitionType: null,
    purchaseDate: null,
    warrantyExpiryDate: null,
    isStored: true,
    isDeleted: false,
    reasonForDeletion: null,
    roomId: null,
    containerId: null,
    ownerId: null,
    releaseDate: null,
    valuationDate: null,
    acquisitionReference: null,
    createdDate: CREATED,
    lastModifiedDate: null,
    rowVersion: RV,
    ...p,
  };
}

